def build_invoice(order, customer):
    subtotal = 0
    for item in order.items:
        line = item.price * item.qty
        if customer.tier == "gold":
            line *= 0.9
        elif customer.tier == "silver":
            line *= 0.95
        subtotal += line
    tax = 0
    if customer.region == "EU":
        tax = subtotal * 0.20
    elif customer.region == "US":
        tax = subtotal * 0.07
    total = subtotal + tax
    return {"subtotal": subtotal, "tax": tax, "total": total}

TIER_DISCOUNT = {"gold": 0.10, "silver": 0.05}
REGION_TAX    = {"EU": 0.20, "US": 0.07}


def calculate_line_total(item, customer_tier: str) -> float:
    base = item.price * item.qty
    discount = TIER_DISCOUNT.get(customer_tier, 0.0)
    return base * (1 - discount)


def calculate_subtotal(items, customer_tier: str) -> float:
    return sum(calculate_line_total(item, customer_tier) for item in items)


def calculate_tax(subtotal: float, region: str) -> float:
    return subtotal * REGION_TAX.get(region, 0.0)


def build_invoice(order, customer):
    subtotal = calculate_subtotal(order.items, customer.tier)
    tax      = calculate_tax(subtotal, customer.region)
    return {"subtotal": subtotal, "tax": tax, "total": subtotal + tax}
